SELECT up.upgrade, up.applicability, count(*) AS count FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = up.bldg_id AND bs."in.nhgis_tract_gisjoin" = up."in.nhgis_tract_gisjoin" AND bs.state = up.state AND bs.upgrade = 0 WHERE up.upgrade != 0 AND bs.applicability = true GROUP BY 1, 2 ORDER BY 1, 2